def solve(well_type, depth):
    if well_type not in ['vertical', 'horizontal']:
        raise ValueError("Invalid well type. Must be 'vertical' or 'horizontal'.")

    if depth < 0:
        raise ValueError("Depth must be a non-negative value.")

    if well_type == 'vertical':
        return f"Drilling a vertical well to {depth} meters."
    elif well_type == 'horizontal':
        return f"Drilling a horizontal well to {depth} meters."
